ValidationRule.errorConditionFormula:
AND(
    NOT(ISBLANK(IBAN__c)),
    IF(
        /* 1. Primeira barreira: Só avança se o formato for perfeito (PT + 23 números) */
        NOT(REGEX(IBAN__c, "^PT[0-9]{23}$")),
        TRUE, /* Se o Regex falhar, dispara logo o erro (TRUE) e não faz a matemática */

        /* 2. O Monstro Matemático (Chunking MOD 97) */
        MOD( 
            VALUE( 
                TEXT( 
                    MOD( 
                        VALUE( 
                            TEXT( 
                                MOD( 
                                    VALUE( 
                                        TEXT( 
                                            MOD( 
                                                /* Primeiros 9 dígitos a seguir ao PT50 */
                                                VALUE( MID(IBAN__c, 5, 9) ), 
                                                97 
                                            ) 
                                        ) & MID(IBAN__c, 14, 7) /* Junta os 7 seguintes */
                                    ), 
                                    97 
                                ) 
                            ) & MID(IBAN__c, 21, 5) & "25" /* Junta os últimos 5 e o P (25) */
                        ), 
                        97 
                    ) 
                ) & "29" & MID(IBAN__c, 3, 2) /* Junta o T (29) e os 2 dígitos de controlo */
            ), 
            97 
        ) <> 1 /* Se o resto final for diferente de 1, dispara o erro! */
    )
)
